    16→
    17→#include "logger/log.h"
    18→#include "command/android/cmd_class.h"
    19→#include "command/android/cmd_print.h"
    20→#include "dex/modifiers.h"
    21→#include "android.h"
    22→#include "runtime/mirror/iftable.h"
    23→#include "api/core.h"
    24→#include <stdio.h>
    25→#include <unistd.h>
    26→#include <getopt.h>
    27→#include <vector>
    28→
    29→int ClassCommand::prepare(int argc, char* const argv[]) {
    30→    if (!CoreApi::IsReady() || !Android::IsSdkReady())
    31→        return Command::FINISH;
    32→
    33→    options.dump_all = true;
    34→    options.show_flag = 0;
    35→    options.format_hex = false;
    36→    options.obj_each_flags = 0;
    37→    options.total_classes = 0;
    38→
    39→    int opt;
    40→    int option_index = 0;
    41→    optind = 0; // reset
    42→    static struct option long_options[] = {
    43→        {"method",  no_argument,       0,  'm'},
    44→        {"static",  no_argument,       0,  's'},
    45→        {"impl",    no_argument,       0,  'i'},
    46→        {"field",   no_argument,       0,  'f'},
    47→        {"hex",     no_argument,       0,  'x'},
    48→        {"app",     no_argument,       0,   1 },
    49→        {"zygote",  no_argument,       0,   2 },
    50→        {"image",   no_argument,       0,   3 },
    51→        {"fake",    no_argument,       0,   4 },
    52→        {0,         0,                 0,   0 },
    53→    };
    54→
    55→    while ((opt = getopt_long(argc, argv, "msifx",
    56→                long_options, &option_index)) != -1) {
    57→        switch (opt) {
    58→            case 'm':
    59→                options.show_flag |= SHOW_METHOD;
    60→                break;
    61→            case 's':
    62→                options.show_flag |= SHOW_STATIC;
    63→                break;
    64→            case 'i':
    65→                options.show_flag |= SHOW_IMPL;
    66→                break;
    67→            case 'f':
    68→                options.show_flag |= SHOW_FIELD;
    69→                break;
    70→            case 'x':
    71→                options.format_hex = true;
    72→                break;
    73→            case 1:
    74→                options.obj_each_flags |= Android::EACH_APP_OBJECTS;
    75→                break;
    76→            case 2:
    77→                options.obj_each_flags |= Android::EACH_ZYGOTE_OBJECTS;
    78→                break;
    79→            case 3:
    80→                options.obj_each_flags |= Android::EACH_IMAGE_OBJECTS;
    81→                break;
    82→            case 4:
    83→                options.obj_each_flags |= Android::EACH_FAKE_OBJECTS;
    84→                break;
    85→        }
    86→    }
    87→    options.optind = optind;
    88→
    89→    if (!options.obj_each_flags) {
    90→        options.obj_each_flags |= Android::EACH_APP_OBJECTS;
    91→        options.obj_each_flags |= Android::EACH_ZYGOTE_OBJECTS;
    92→        options.obj_each_flags |= Android::EACH_IMAGE_OBJECTS;
    93→        options.obj_each_flags |= Android::EACH_FAKE_OBJECTS;
    94→    }
